    it('should return 500 when service throws', async () => {
      const brokenService = {
        getDashboard: () => { throw new Error('Database connection lost'); },
        getMetric: () => { throw new Error('Database connection lost'); },
        getTimeSeries: () => { throw new Error('Database connection lost'); },
        getTopProducts: () => { throw new Error('Database connection lost'); },
      } as unknown as AnalyticsService;

      const brokenRoutes = createAnalyticsRoutes(brokenService);

      // Test all 4 endpoints return 500
      const dashboard = await findRoute(brokenRoutes, '/api/analytics/dashboard').handler(
        makeRequest({ query: { startDate: '2025-01-01T00:00:00Z', endDate: '2025-01-31T23:59:59Z' } })
      );
      expect(dashboard.status).toBe(500);
      expect((dashboard.data as { error: string }).error).not.toContain('Database connection lost'); // error details hidden

      const metric = await findRoute(brokenRoutes, '/api/analytics/metrics/:type').handler(
