      );
      expect(metric.status).toBe(500);

      const timeseries = await findRoute(brokenRoutes, '/api/analytics/timeseries').handler(
        makeRequest({ query: { metric: 'orders', startDate: '2025-01-01T00:00:00Z', endDate: '2025-01-31T23:59:59Z' } })
      );
      expect(timeseries.status).toBe(500);

      const topProducts = await findRoute(brokenRoutes, '/api/analytics/top-products').handler(
        makeRequest({ query: { startDate: '2025-01-01T00:00:00Z', endDate: '2025-01-31T23:59:59Z' } })
      );
      expect(topProducts.status).toBe(500);
    });
  });

