    it('should handle concurrent calls without state leaking between them', async () => {
      seedTestData(orderRepo, userRepo);

      const dateQuery = {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-01-31T23:59:59Z',
      };

      const route = findRoute(routes, '/api/analytics/dashboard');

      // Run multiple concurrent requests
      const [res1, res2, res3] = await Promise.all([
        route.handler(makeRequest({ query: dateQuery })),
        route.handler(makeRequest({ query: dateQuery })),
        route.handler(makeRequest({ query: dateQuery })),
      ]);

      // All should return identical results
      const data1 = res1.data as DashboardData;
      const data2 = res2.data as DashboardData;
      const data3 = res3.data as DashboardData;

      expect(data1.metrics.find((m) => m.type === 'revenue')?.value)
        .toBe(data2.metrics.find((m) => m.type === 'revenue')?.value);
      expect(data2.metrics.find((m) => m.type === 'revenue')?.value)
        .toBe(data3.metrics.find((m) => m.type === 'revenue')?.value);
    });
  });
